        ctx.lineTo(nv.x, nv.y);
        if ((uIn && vElim) || (vIn && uElim)) {
            ctx.strokeStyle = 'rgba(0,230,118,0.3)';
            ctx.lineWidth = 2;
        } else {
            ctx.strokeStyle = 'rgba(139,148,158,0.25)';
            ctx.lineWidth = 1;
        }
        ctx.stroke();
    }

    // nodes
    for (const nd of nodes) {
        const v = nd.id;
        ctx.beginPath();
        ctx.arc(nd.x, nd.y, 18, 0, Math.PI*2);
        if (indepSet.has(v)) {
            ctx.fillStyle = '#00e676';
            ctx.globalAlpha = 1;
        } else if (v === candidate) {
            ctx.fillStyle = '#ffd740';
            ctx.globalAlpha = 1;
        } else if (eliminated.has(v)) {
            ctx.fillStyle = '#8b949e';
            ctx.globalAlpha = 0.4;
        } else {
            ctx.fillStyle = '#58a6ff';
            ctx.globalAlpha = 0.8;
        }
        ctx.fill();
        ctx.globalAlpha = 1;
        ctx.strokeStyle = v === hoverNode ? '#fff' : 'rgba(255,255,255,0.15)';
        ctx.lineWidth = v === hoverNode ? 2.5 : 1;
        ctx.stroke();

        // label
        ctx.fillStyle = indepSet.has(v) || v === candidate ? '#000' : '#fff';
        ctx.font = 'bold 13px system-ui, sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(v, nd.x, nd.y);
    }
}

/* ── Interaction ── */
function getNode(mx, my) {
    for (let i = nodes.length-1; i >= 0; i--) {
        const dx = mx - nodes[i].x, dy = my - nodes[i].y;
        if (dx*dx + dy*dy < 400) return i;
    }
    return -1;
}

function canvasPos(e) {
    const r = canvas.getBoundingClientRect();
    return { x: (e.clientX - r.left) * (canvas.width / r.width), y: (e.clientY - r.top) * (canvas.height / r.height) };
}

canvas.addEventListener('mousedown', e => {
    const p = canvasPos(e);
    const i = getNode(p.x, p.y);
    if (i >= 0) { dragNode = i; dragOffX = p.x - nodes[i].x; dragOffY = p.y - nodes[i].y; canvas.style.cursor = 'grabbing'; }
});

canvas.addEventListener('mousemove', e => {
    const p = canvasPos(e);
    if (dragNode >= 0) {
        nodes[dragNode].x = p.x - dragOffX;
        nodes[dragNode].y = p.y - dragOffY;
        draw();
        return;
    }
    const i = getNode(p.x, p.y);
    if (i >= 0 && i !== hoverNode) {
        hoverNode = i;
        const v = nodes[i].id;
        const deg = adj[v] ? adj[v].length : 0;
        let status = 'available';
        if (indepSet.has(v)) status = 'in independent set';
        else if (eliminated.has(v)) status = 'eliminated';
        else if (v === candidate) status = 'candidate';
        tooltip.style.display = 'block';
        tooltip.innerHTML = `<strong>v${v}</strong><br>Degree: ${deg}<br>Status: ${status}`;
        tooltip.style.left = (e.clientX + 14) + 'px';
        tooltip.style.top = (e.clientY + 14) + 'px';
        draw();
    } else if (i < 0 && hoverNode >= 0) {
        hoverNode = -1;
        tooltip.style.display = 'none';
        draw();
    }
});

canvas.addEventListener('mouseup', () => { dragNode = -1; canvas.style.cursor = 'grab'; });
canvas.addEventListener('mouseleave', () => { hoverNode = -1; tooltip.style.display = 'none'; dragNode = -1; draw(); });

/* ── Load custom graph ── */
function loadCustom() {
    const txt = document.getElementById('textInput').value.trim();
    if (!txt) return;
    const es = [], vs = new Set();
    for (const line of txt.split('\n')) {
        const parts = line.trim().split(/[\s,]+/).map(Number);
        if (parts.length >= 2 && !isNaN(parts[0]) && !isNaN(parts[1])) {
            es.push([parts[0], parts[1]]);
            vs.add(parts[0]); vs.add(parts[1]);
        }
    }
    const vArr = [...vs].sort((a,b)=>a-b);
    const remap = {}; vArr.forEach((v,i) => remap[v] = i);
    const n = vArr.length;
    nodes = layoutCircle(n, canvas.width/2, canvas.height/2, Math.min(canvas.width, canvas.height)*0.35);
    edges = es.map(([u,v]) => [remap[u], remap[v]]);
    buildAdj();
    resetState();
    updateStats();
    draw();
    document.querySelectorAll('.preset-btn').forEach(b => b.classList.remove('active'));
}

/* ── Export ── */
function exportJSON() {
    const data = { independentSet: [...indepSet].sort((a,b)=>a-b), size: indepSet.size, vertices: nodes.length, edges: edges.length };
    navigator.clipboard.writeText(JSON.stringify(data, null, 2)).then(() => {
        const btn = document.getElementById('btnExport');
        const orig = btn.textContent;
        btn.textContent = '✓ Copied!';
        setTimeout(() => btn.textContent = orig, 1500);
    });
}

/* ── Wiring ── */
document.getElementById('btnRun').onclick = startRun;
document.getElementById('btnStep').onclick = stepOnce;
document.getElementById('btnReset').onclick = () => { resetState(); draw(); };
document.getElementById('btnLoad').onclick = loadCustom;
document.getElementById('btnExport').onclick = exportJSON;
document.querySelectorAll('.preset-btn').forEach(b => b.onclick = () => loadPreset(b.dataset.preset));

// Resize
function resize() {
    const main = canvas.parentElement;
    const w = main.clientWidth;
    canvas.width = w;
    canvas.height = Math.max(500, w * 0.68);
    draw();
}
window.addEventListener('resize', resize);

// Init
loadPreset('path5');
resize();

